// JavaScript example: deterministic bucketing by user_id
function bucket(userId, buckets) {
  let h = 0;
  for (let i = 0; i < userId.length; i++) h = (h * 31 + userId.charCodeAt(i)) >>> 0;
  return h % buckets;
}
```

