function trimmedMean(arr, trim=0.1){
  const sorted = arr.slice().sort((a,b)=>a-b);
  const n = sorted.length;
  const k = Math.floor(n * trim);
  const sliced = sorted.slice(k, n - k);
  return sliced.reduce((a,b)=>a+b,0) / sliced.length;
}
```

